using UniversityCourseCatalog.Models;

namespace UniversityCourseCatalog.Services;

public class CatalogService
{
    private readonly List<Department> _departments;
    private readonly List<Instructor> _instructors;
    private readonly List<Course> _courses;
    private readonly List<EnrollmentRequest> _enrollments = new();

    public CatalogService()
    {
        _departments = new List<Department>
        {
            new() { Id = 1, Code = "CS", Name = "Computer Science", Description = "Study of computation, algorithms, and information systems." },
            new() { Id = 2, Code = "MATH", Name = "Mathematics", Description = "Pure and applied mathematics, statistics, and data analysis." },
            new() { Id = 3, Code = "PHYS", Name = "Physics", Description = "Study of matter, energy, and the fundamental forces of nature." },
            new() { Id = 4, Code = "ENG", Name = "English", Description = "Literature, writing, rhetoric, and language studies." },
            new() { Id = 5, Code = "HIST", Name = "History", Description = "World history, civilizations, and historical analysis." },
            new() { Id = 6, Code = "BIO", Name = "Biology", Description = "Life sciences including molecular biology, ecology, and genetics." },
        };

        _instructors = new List<Instructor>
        {
            new() { Id = 1, Name = "Dr. Alice Chen", Title = "Professor of Computer Science", Email = "achen@university.edu",
                Bio = "Dr. Chen specializes in artificial intelligence and machine learning. She has published over 50 peer-reviewed papers and leads the university's AI research lab.",
                PhotoUrl = "" },
            new() { Id = 2, Name = "Dr. Robert Martinez", Title = "Associate Professor of Computer Science", Email = "rmartinez@university.edu",
                Bio = "Dr. Martinez focuses on software engineering and distributed systems. He spent 10 years in industry at leading tech companies before joining academia.",
                PhotoUrl = "" },
            new() { Id = 3, Name = "Dr. Sarah Johnson", Title = "Professor of Mathematics", Email = "sjohnson@university.edu",
                Bio = "Dr. Johnson is an award-winning educator specializing in abstract algebra and number theory. She is a recipient of the National Teaching Excellence Award.",
                PhotoUrl = "" },
            new() { Id = 4, Name = "Dr. James Wilson", Title = "Associate Professor of Physics", Email = "jwilson@university.edu",
                Bio = "Dr. Wilson researches quantum mechanics and particle physics. He previously worked at CERN and has contributed to several landmark experiments.",
                PhotoUrl = "" },
            new() { Id = 5, Name = "Prof. Emily Brooks", Title = "Professor of English", Email = "ebrooks@university.edu",
                Bio = "Prof. Brooks is a noted literary critic and author, specializing in 19th-century American literature and creative writing pedagogy.",
                PhotoUrl = "" },
            new() { Id = 6, Name = "Dr. Michael Torres", Title = "Associate Professor of History", Email = "mtorres@university.edu",
                Bio = "Dr. Torres studies modern European history and the history of science. He is the author of three books on the Enlightenment era.",
                PhotoUrl = "" },
            new() { Id = 7, Name = "Dr. Karen Liu", Title = "Professor of Biology", Email = "kliu@university.edu",
                Bio = "Dr. Liu is a molecular biologist whose research focuses on gene expression and CRISPR technology. She directs the Genomics Center.",
                PhotoUrl = "" },
            new() { Id = 8, Name = "Dr. David Park", Title = "Associate Professor of Mathematics", Email = "dpark@university.edu",
                Bio = "Dr. Park specializes in applied statistics and data science. He collaborates with industry partners on real-world analytics projects.",
                PhotoUrl = "" },
        };

        _courses = new List<Course>
        {
            // Computer Science
            new() { Id = 1, Code = "CS 101", Title = "Introduction to Computer Science", Credits = 3, DepartmentId = 1, InstructorId = 1, IsFeatured = true,
                Description = "A broad introduction to computer science covering computational thinking, basic programming in Python, data representation, and an overview of major CS subfields.",
                Schedule = "Mon/Wed/Fri 9:00–9:50 AM", Location = "Science Hall 201", MaxEnrollment = 120, CurrentEnrollment = 98 },
            new() { Id = 2, Code = "CS 201", Title = "Data Structures & Algorithms", Credits = 4, DepartmentId = 1, InstructorId = 2,
                Description = "Study of fundamental data structures (arrays, linked lists, trees, graphs, hash tables) and algorithm design techniques including sorting, searching, and complexity analysis.",
                Schedule = "Tue/Thu 10:30–11:50 AM", Location = "Science Hall 305", MaxEnrollment = 60, CurrentEnrollment = 55 },
            new() { Id = 3, Code = "CS 310", Title = "Artificial Intelligence", Credits = 3, DepartmentId = 1, InstructorId = 1, IsFeatured = true,
                Description = "Introduction to AI concepts including search algorithms, knowledge representation, machine learning fundamentals, natural language processing, and ethical considerations in AI.",
