@page "/courses"
@inject UniversityCourseCatalog.Services.CatalogService Catalog
@inject NavigationManager Navigation
@rendermode InteractiveServer

<PageTitle>Browse Courses</PageTitle>

<h1 class="mb-4"><i class="bi bi-journal-bookmark"></i> Browse Courses</h1>

<div class="row mb-4">
    <div class="col-md-6">
        <div class="input-group">
            <span class="input-group-text"><i class="bi bi-search"></i></span>
            <input type="text" class="form-control" placeholder="Search by title, code, or keyword…"
                   @bind="SearchTerm" @bind:event="oninput" />
            @if (!string.IsNullOrWhiteSpace(SearchTerm))
            {
                <button class="btn btn-outline-secondary" @onclick="ClearSearch">
                    <i class="bi bi-x-lg"></i>
                </button>
            }
        </div>
    </div>
    <div class="col-md-4">
        <select class="form-select" @bind="SelectedDepartmentId">
            <option value="0">All Departments</option>
            @foreach (var dept in Departments)
            {
                <option value="@dept.Id">@dept.Name (@dept.Code)</option>
            }
        </select>
    </div>
    <div class="col-md-2 d-flex align-items-center">
        <span class="text-muted">@FilteredCourses.Count course(s)</span>
    </div>
</div>

@if (FilteredCourses.Count == 0)
{
    <div class="alert alert-info">
        <i class="bi bi-info-circle"></i> No courses match your search criteria. Try adjusting your filters.
    </div>
}
else
{
    <div class="table-responsive">
        <table class="table table-hover align-middle">
            <thead class="table-light">
                <tr>
                    <th>Code</th>
                    <th>Title</th>
                    <th>Department</th>
                    <th>Credits</th>
                    <th>Schedule</th>
                    <th>Enrollment</th>
                    <th></th>
                </tr>
            </thead>
            <tbody>
                @foreach (var course in FilteredCourses)
                {
                    <tr>
                        <td><span class="badge bg-secondary">@course.Code</span></td>
                        <td><strong>@course.Title</strong></td>
                        <td>@Catalog.GetDepartmentName(course.DepartmentId)</td>
                        <td>@course.Credits</td>
                        <td><small>@course.Schedule</small></td>
                        <td>
                            @{
                                var pct = course.MaxEnrollment > 0 ? (double)course.CurrentEnrollment / course.MaxEnrollment * 100 : 0;
                                var barClass = pct >= 90 ? "bg-danger" : pct >= 70 ? "bg-warning" : "bg-success";
                            }
                            <div class="progress" style="min-width:80px; height:18px;">
                                <div class="progress-bar @barClass" style="width: @pct.ToString("F0")%;"
                                     role="progressbar">
                                    @course.CurrentEnrollment/@course.MaxEnrollment
                                </div>
                            </div>
                        </td>
                        <td><a href="courses/@course.Id" class="btn btn-sm btn-outline-primary">Details</a></td>
                    </tr>
                }
            </tbody>
        </table>
    </div>
}

